1	import { useCallback, useEffect, useRef, useState } from "react";
2	import { ParticipantKind, Room, RoomEvent, type RemoteParticipant } from "livekit-client";
3	import type {
4	  DebateFinalScore,
5	  DebateTurn,
6	  DebateTurnScore,
7	  FactCheckFlag,
8	  TranscriptSession,
9	} from "@/lib/types";
10	
11	// Shape of the JSON we publish from the Python agent (see backend/src/agent.py).
12	// Frontend renders transcripts live; flag verdicts will land here too once Lukas's stream is wired.
13	type DataChannelMessage =
14	  | { type: "transcript"; text: string; is_final: boolean }
15	  | { type: "flag"; claim: string; verdict: string; reasoning: string; sources: string[] }
16	  | {
17	      type: "debate_turn";
18	      role: "user" | "model";
19	      turnId: string;
20	      text: string;
21	      timestamp: string;
22	      sources?: string[];
23	    }
24	  | {
25	      type: "debate_score";
26	      turnId: string;
27	      scores: {
28	        logicalConsistency: number;
29	        evidenceQuality: number;
30	        rebuttalEffectiveness: number;
31	        clarityStructure: number;
32	        responsiveness: number;
33	      };
34	      strongClaims: Array<{ claim: string; strength: "strong"; reason: string }>;
35	      weakClaims: Array<{ claim: string; strength: "weak"; reason: string }>;
36	      coachingSuggestion: string;
37	    }
38	  | {
39	      type: "debate_final_score";
40	      overall: number;
41	      scores: {
42	        logicalConsistency: number;
43	        evidenceQuality: number;
44	        rebuttalEffectiveness: number;
45	        clarityStructure: number;
46	        responsiveness: number;
47	      };
48	      summary: string;
49	    }
50	  | Record<string, unknown>;
51	
52	type ConnectionStatus = "idle" | "connecting" | "connected" | "error";
53	type AppMode = "analysis" | "debate";
54	
55	function formatTimestamp(date: Date): string {
56	  return date.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", second: "2-digit" });
57	}
58	
59	function newSessionId(): string {
60	  return typeof crypto !== "undefined" && "randomUUID" in crypto
61	    ? crypto.randomUUID()
62	    : `session-${Date.now()}-${Math.random().toString(36).slice(2)}`;
63	}
64	
65	// Match the backend's normalization (agent.py:normalize_claim) so dedup keys
66	// agree on both ends. Same claim with different trailing punctuation/case is
67	// treated as one claim; verdict updates replace the existing card.
68	function normalizeClaim(claim: string): string {
69	  return claim.toLowerCase().replace(/^[\s.,!?;:'"`-]+|[\s.,!?;:'"`-]+$/g, "");
70	}
71	
72	const LIVEKIT_URL = import.meta.env.VITE_LIVEKIT_URL as string | undefined;
73	const LIVEKIT_TOKEN = import.meta.env.VITE_LIVEKIT_TOKEN as string | undefined;
74	
75	// Connect to a LiveKit room, publish the mic, and accumulate every Data Channel
76	// transcript event into the *current* session block. Each Connect→Disconnect
77	// cycle gets its own block; older blocks are preserved so the UI can stack them.
78	export function useLiveKitRoom(mode: AppMode = "analysis") {
79	  const roomRef = useRef<Room | null>(null);
80	  const audioContainerRef = useRef<HTMLDivElement | null>(null);
81	  const audioElementsRef = useRef<Map<string, HTMLMediaElement>>(new Map());
82	  const modeRef = useRef<AppMode>(mode);
83	  const [status, setStatus] = useState<ConnectionStatus>("idle");
84	  const [error, setError] = useState<string | null>(null);
85	  const [sessions, setSessions] = useState<TranscriptSession[]>([]);
86	  const [flags, setFlags] = useState<FactCheckFlag[]>([]);
87	  const [debateTurns, setDebateTurns] = useState<DebateTurn[]>([]);
88	  const [debateScores, setDebateScores] = useState<DebateTurnScore[]>([]);
89	  const [debateFinalScore, setDebateFinalScore] = useState<DebateFinalScore | null>(null);
90	
91	  const ensureAudioContainer = useCallback((): HTMLDivElement | null => {
92	    if (typeof document === "undefined") return null;
93	    if (audioContainerRef.current) return audioContainerRef.current;
94	
95	    const container = document.createElement("div");
96	    container.id = "livekit-remote-audio";
97	    container.setAttribute("aria-hidden", "true");
98	    container.style.position = "fixed";
99	    container.style.width = "1px";
100	    container.style.height = "1px";
101	    container.style.overflow = "hidden";
102	    container.style.opacity = "0";
103	    container.style.pointerEvents = "none";
104	    document.body.appendChild(container);
105	    audioContainerRef.current = container;
106	    return container;
107	  }, []);
108	
109	  const cleanupRemoteAudio = useCallback(() => {
110	    audioElementsRef.current.forEach((element) => {
111	      try {
112	        element.pause();
113	      } catch {
114	        // no-op
115	      }
116	      if (element.parentElement) element.parentElement.removeChild(element);
117	    });
118	    audioElementsRef.current.clear();
119	
120	    if (audioContainerRef.current?.parentElement) {
121	      audioContainerRef.current.parentElement.removeChild(audioContainerRef.current);
122	    }
123	    audioContainerRef.current = null;
124	  }, []);
125	
126	  const publishAppMode = useCallback(async (nextMode: AppMode) => {
127	    const room = roomRef.current;
128	    if (!room) return;
129	
130	    const payload = new TextEncoder().encode(
131	      JSON.stringify({ type: "app_mode", mode: nextMode }),
132	    );
133	
134	    try {
135	      await room.localParticipant.publishData(payload, {
136	        reliable: true,
137	        topic: "control",
138	      });
139	      console.log("[livekit control] app mode published", nextMode);
140	    } catch (err) {
141	      console.warn("[livekit control] failed to publish app mode", err);
142	    }
143	  }, []);
144	
145	  useEffect(() => {
146	    modeRef.current = mode;
147	    if (mode === "debate") {
148	      setFlags([]);
149	    }
150	  }, [mode]);
151	
152	  const clearDebate = useCallback(() => {
153	    setDebateTurns([]);
154	    setDebateScores([]);
155	    setDebateFinalScore(null);
156	  }, []);
157	
158	  useEffect(() => {
159	    void publishAppMode(mode);
160	  }, [mode, publishAppMode]);
161	
162	  // Establish the underlying LiveKit room connection once and keep it open
163	  // for the page lifetime. This avoids the dispatch cold-start delay every
164	  // time the user toggles Connect/Disconnect.
165	  const ensureRoomConnected = useCallback(async (): Promise<Room | null> => {
166	    if (roomRef.current) {
167	      console.log("[livekit] reusing existing room instance");
168	      return roomRef.current;
169	    }
170	
171	    if (!LIVEKIT_URL || !LIVEKIT_TOKEN) {
172	      const msg = "Missing VITE_LIVEKIT_URL or VITE_LIVEKIT_TOKEN in .env";
173	      console.error(msg);
174	      setError(msg);
175	      setStatus("error");
176	      return null;
177	    }
178	
179	    console.log("[livekit] creating room", {
180	      url: LIVEKIT_URL,
181	      hasToken: Boolean(LIVEKIT_TOKEN),
182	    });
183	
184	    const room = new Room({
185	      // Auto-tune mic settings for speech use case
186	      adaptiveStream: true,
187	      dynacast: true,
188	    });
189	
190	    // Decode Data Channel payloads as UTF-8 JSON. The agent publishes JSON
191	    // on topic "transcript" — later we'll route by `topic` to different UI.
192	    const decoder = new TextDecoder();
193	    room.on(
194	      RoomEvent.DataReceived,
195	      (payload: Uint8Array, participant?: RemoteParticipant, _kind?, topic?: string) => {
196	        let message: DataChannelMessage;
197	        try {
198	          message = JSON.parse(decoder.decode(payload)) as DataChannelMessage;
199	        } catch (err) {
200	          console.warn("[livekit data] non-JSON payload", err);
201	          return;
202	        }
203	
204	        console.log("[livekit data]", { topic, from: participant?.identity, message });
205	
206	        if (
207	          typeof message === "object" &&
208	          message !== null &&
209	          "type" in message &&
210	          message.type === "transcript" &&
211	          typeof (message as { text?: unknown }).text === "string"
212	        ) {
213	          const transcript = message as { type: "transcript"; text: string; is_final: boolean };
214	          setSessions((previousSessions) => {
215	            // Transcripts arriving without a current session means the mic was
216	            // muted mid-flush — append to the most recent block anyway so
217	            // Deepgram's trailing final isn't lost.
218	            if (previousSessions.length === 0) return previousSessions;
219	
220	            const nextSessions = [...previousSessions];
221	            const currentSession = { ...nextSessions[nextSessions.length - 1] };
222	
223	            if (transcript.is_final) {
224	              // Commit this utterance into the running paragraph and clear the interim slot.
225	              currentSession.text = currentSession.text
226	                ? `${currentSession.text} ${transcript.text}`
227	                : transcript.text;
228	              currentSession.pendingText = "";
229	            } else {
230	              // Interim — overwrite previous interim text for this utterance.
231	              currentSession.pendingText = transcript.text;
232	            }
233	
234	            nextSessions[nextSessions.length - 1] = currentSession;
235	            console.log("[livekit data] transcript applied", {
236	              isFinal: transcript.is_final,
237	              textLength: transcript.text.length,
238	              sessionId: currentSession.id,
239	              committedLength: currentSession.text.length,
240	              pendingLength: currentSession.pendingText.length,
241	            });
242	            return nextSessions;
243	          });
244	          return;
245	        }
246	
247	        if (
248	          typeof message === "object" &&
249	          message !== null &&
250	          "type" in message &&
251	          message.type === "flag" &&
252	          typeof (message as { claim?: unknown }).claim === "string"
253	        ) {
254	          if (modeRef.current !== "analysis") return;
255	          const flagMessage = message as FactCheckFlag;
256	          setFlags((prev) => {
257	            const incoming = normalizeClaim(flagMessage.claim);
258	            const idx = prev.findIndex((f) => normalizeClaim(f.claim) === incoming);
259	            if (idx >= 0) {
260	              if (prev[idx].verdict === flagMessage.verdict) return prev;
261	              const next = [...prev];
262	              next[idx] = flagMessage;
263	              return next;
264	            }
265	            return [...prev, flagMessage];
266	          });
267	          return;
268	        }
269	
270	        if (
271	          typeof message === "object" &&
