1	import React from "react";
2	import type { FactCheckFlag } from "@/lib/types";
3	
4	interface MeterProps {
5	  flags: FactCheckFlag[];
6	  activeSessionId: string | null;
7	  rightSlot?: React.ReactNode;
8	}
9	
10	export const Meter: React.FC<MeterProps> = ({ flags, activeSessionId, rightSlot }) => {
11	  // Only calculate meter state for the currently active session
12	  const sessionFlags = flags.filter((f) => f.sessionId === activeSessionId);
13	  const total = sessionFlags.length;
14	
15	  const counts = {
16	    TRUE: 0,
17	    FALSE: 0,
18	    "PARTIALLY TRUE": 0,
19	    INCONCLUSIVE: 0,
20	  };
21	
22	  sessionFlags.forEach((f) => {
23	    if (f.verdict in counts) {
24	      counts[f.verdict as keyof typeof counts]++;
25	    }
26	  });
27	
28	  return (
29	    <div className="w-full bg-card border-b border-border z-10">
30	      <div className="flex w-full flex-col md:flex-row">
31	        <div className="w-full md:w-1/2 p-4 flex flex-col gap-3">
32	          <div className="flex justify-between items-baseline gap-3">
33	            <span className="text-[10px] font-semibold uppercase tracking-[0.2em] text-muted-foreground">
34	              Live Fact Check Meter
35	            </span>
36	            <span className="text-[10px] font-semibold uppercase tracking-[0.15em] text-muted-foreground">
37	              Claims: <span className="text-foreground">{total}</span>
38	            </span>
39	          </div>
40	
41	          <div className="flex h-2 w-full overflow-hidden rounded-sm border border-border bg-muted">
42	            {total === 0 ? (
43	              <div className="h-full w-full bg-muted" />
44	            ) : (
45	              <>
46	                <div
47	                  style={{ width: `${(counts["TRUE"] / total) * 100}%` }}
48	                  className="bg-foreground transition-all duration-500"
49	                  title={`True: ${counts["TRUE"]}`}
50	                />
51	                <div
52	                  style={{ width: `${(counts["PARTIALLY TRUE"] / total) * 100}%` }}
53	                  className="bg-accent transition-all duration-500"
54	                  title={`Partially True: ${counts["PARTIALLY TRUE"]}`}
55	                />
56	                <div
57	                  style={{ width: `${(counts["FALSE"] / total) * 100}%` }}
58	                  className="bg-destructive transition-all duration-500"
59	                  title={`False: ${counts["FALSE"]}`}
60	                />
61	                <div
62	                  style={{ width: `${(counts["INCONCLUSIVE"] / total) * 100}%` }}
63	                  className="bg-muted-foreground/60 transition-all duration-500"
64	                  title={`Inconclusive: ${counts["INCONCLUSIVE"]}`}
65	                />
66	              </>
67	            )}
68	          </div>
69	
70	          <div className="flex flex-col gap-1 text-[10px] font-mono uppercase tracking-wider">
71	            <LegendItem swatchClass="bg-foreground" label="True" value={counts["TRUE"]} />
72	            <LegendItem swatchClass="bg-accent" label="Partial" value={counts["PARTIALLY TRUE"]} />
73	            <LegendItem swatchClass="bg-destructive" label="False" value={counts["FALSE"]} />
74	            <LegendItem swatchClass="bg-muted-foreground/60" label="N/A" value={counts["INCONCLUSIVE"]} />
75	          </div>
76	        </div>
77	
78	        {rightSlot ? (
79	          <div className="w-full md:w-1/2 p-4 md:border-l border-border">
80	            {rightSlot}
81	          </div>
82	        ) : null}
83	      </div>
