2	import { ExternalLink } from "lucide-react";
3	import { Badge } from "@/components/ui/badge";
4	import { cn } from "@/lib/utils";
5	import type { FactCheckFlag, FactCheckVerdict } from "@/lib/types";
6	
7	const verdictLabel: Record<FactCheckVerdict, string> = {
8	  "TRUE": "True",
9	  "FALSE": "False",
10	  "PARTIALLY TRUE": "Partially True",
11	  "INCONCLUSIVE": "Inconclusive",
12	};
13	
14	const verdictStyles: Record<FactCheckVerdict, { card: string; badge: string; quote: string }> = {
15	  "TRUE": {
16	    card: "border-green-300 bg-green-50",
17	    badge: "border-transparent bg-green-600 text-white hover:bg-green-600/90",
18	    quote: "border-green-500",
19	  },
20	  "FALSE": {
21	    card: "border-red-300 bg-red-50",
22	    badge: "border-transparent bg-red-600 text-white hover:bg-red-600/90",
23	    quote: "border-red-500",
24	  },
25	  "PARTIALLY TRUE": {
26	    card: "border-orange-300 bg-orange-50",
27	    badge: "border-transparent bg-orange-500 text-white hover:bg-orange-500/90",
28	    quote: "border-orange-500",
29	  },
30	  "INCONCLUSIVE": {
31	    card: "border-slate-300 bg-slate-100",
32	    badge: "border-transparent bg-slate-500 text-white hover:bg-slate-500/90",
33	    quote: "border-slate-400",
34	  },
35	};
36	
37	// Animate text appearing one character at a time so each flag feels like it's
38	// streaming in, even though the payload arrives as a single data-channel message.
39	function useTypewriter(text: string, speed: number, enabled: boolean) {
40	  const [displayed, setDisplayed] = useState("");
41	
42	  useEffect(() => {
43	    if (!enabled) {
44	      setDisplayed("");
45	      return;
46	    }
47	    setDisplayed("");
48	    if (!text) return;
49	
50	    let i = 0;
51	    const interval = setInterval(() => {
52	      i++;
53	      setDisplayed(text.slice(0, i));
54	      if (i >= text.length) clearInterval(interval);
55	    }, speed);
56	
57	    return () => clearInterval(interval);
58	  }, [text, speed, enabled]);
59	
60	  return { displayed, isDone: enabled && displayed.length === text.length };
61	}
62	
63	type FactCheckCardProps = {
64	  flag: FactCheckFlag;
65	};
66	
67	export function FactCheckCard({ flag }: FactCheckCardProps) {
68	  const verdict = flag.verdict as FactCheckVerdict;
69	  const styles = verdictStyles[verdict] ?? verdictStyles["INCONCLUSIVE"];
70	
71	  const { displayed: claimText, isDone: claimDone } = useTypewriter(flag.claim, 18, true);
72	  const { displayed: reasoningText, isDone: reasoningDone } = useTypewriter(flag.reasoning, 12, claimDone);
73	
74	  return (
75	    <article className={cn("rounded-md border p-4 text-card-foreground shadow-sm transition-colors", styles.card)}>
76	      <div className="mb-3 flex items-start justify-between gap-3">
77	        <div className="flex flex-wrap items-center gap-1.5">
78	          <Badge className={styles.badge}>{verdictLabel[verdict] ?? verdict}</Badge>
79	          {flag.used_trusted_context && (
80	            <span
81	              className="rounded-full border border-primary/40 bg-primary/10 px-2 py-0.5 text-[10px] font-semibold uppercase tracking-wide text-primary"
82	              title="This verdict was likely informed by your uploaded context."
83	            >
84	              from context
85	            </span>
