1	import { useCallback, useEffect, useRef, useState } from "react";
2	import { ParticipantKind, Room, RoomEvent, type RemoteParticipant } from "livekit-client";
3	import type { TranscriptSession, FactCheckFlag } from "@/lib/types";
4	
5	// Shape of the JSON we publish from / receive on the LiveKit data channel.
6	type DataChannelMessage =
7	  | { type: "transcript"; text: string; is_final: boolean }
8	  | {
9	      type: "flag";
10	      claim: string;
11	      verdict: string;
12	      reasoning: string;
13	      sources: string[];
14	      used_trusted_context?: boolean;
15	    }
16	  | {
17	      type: "context_status";
18	      phase: "loading" | "vetting" | "ready" | "error";
19	      kept?: number;
20	      total?: number;
21	      error?: string;
22	    }
23	  | Record<string, unknown>;
24	
25	type ConnectionStatus = "idle" | "connecting" | "connected" | "error";
26	
27	export type ContextMode = "gospel" | "nuanced";
28	
29	// `ContextStatus` is a discriminated union so each phase can carry its own
30	// shape of data without optional fields everywhere downstream.
31	export type ContextStatus =
32	  | { phase: "none" }
33	  | { phase: "staged"; mode: ContextMode; statements: string[]; fileName: string }
34	  | { phase: "loading"; mode: ContextMode; total: number; fileName: string }
35	  | {
36	      phase: "vetting";
37	      mode: ContextMode;
38	      kept: number;
39	      total: number;
40	      fileName: string;
41	    }
42	  | {
43	      phase: "ready";
44	      mode: ContextMode;
45	      kept: number;
46	      total: number;
47	      fileName: string;
48	    }
49	  | { phase: "error"; error: string };
50	
51	const MAX_CONTEXT_FILE_BYTES = 32 * 1024;
52	const AGENT_WAIT_TIMEOUT_MS = 8000;
53	
54	function formatTimestamp(date: Date): string {
55	  return date.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", second: "2-digit" });
56	}
57	
58	function newSessionId(): string {
59	  return typeof crypto !== "undefined" && "randomUUID" in crypto
60	    ? crypto.randomUUID()
61	    : `session-${Date.now()}-${Math.random().toString(36).slice(2)}`;
62	}
63	
64	// Match backend/src/agent.py:normalize_claim so dedup keys agree on both ends.
65	function normalizeClaim(claim: string): string {
66	  return claim.toLowerCase().replace(/^[\s.,!?;:'"`-]+|[\s.,!?;:'"`-]+$/g, "");
67	}
68	
69	// Mirrors backend/src/context_loader.py:parse_context_text — one statement per
70	// line, "#" lines and blanks are dropped.
71	function parseStatements(text: string): string[] {
72	  return text
73	    .split(/\r?\n/)
74	    .map((l) => l.trim())
75	    .filter((l) => l.length > 0 && !l.startsWith("#"));
76	}
77	
78	const LIVEKIT_URL = import.meta.env.VITE_LIVEKIT_URL as string | undefined;
79	const LIVEKIT_TOKEN = import.meta.env.VITE_LIVEKIT_TOKEN as string | undefined;
80	
81	export function useLiveKitRoom() {
82	  const roomRef = useRef<Room | null>(null);
83	  // Mirror activeSessionId into a ref so the data-channel callback (created
84	  // once inside ensureRoomConnected) can read the current id without us
85	  // re-binding the room handlers on every connect.
86	  const activeSessionIdRef = useRef<string | null>(null);
87	
88	  const [status, setStatus] = useState<ConnectionStatus>("idle");
89	  const [error, setError] = useState<string | null>(null);
90	  const [sessions, setSessions] = useState<TranscriptSession[]>([]);
91	  const [flags, setFlags] = useState<FactCheckFlag[]>([]);
92	  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
93	  const [contextStatus, setContextStatus] = useState<ContextStatus>({ phase: "none" });
94	
95	  // The connect flow needs the latest contextStatus snapshot but doesn't want
96	  // to re-create on every change. Mirror it into a ref so callbacks can read
97	  // current state without becoming a dependency.
98	  const contextStatusRef = useRef(contextStatus);
99	  useEffect(() => {
100	    contextStatusRef.current = contextStatus;
101	  }, [contextStatus]);
102	
103	  const ensureRoomConnected = useCallback(async (): Promise<Room | null> => {
104	    if (roomRef.current) {
105	      console.log("[livekit] reusing existing room instance");
106	      return roomRef.current;
107	    }
108	
109	    if (!LIVEKIT_URL || !LIVEKIT_TOKEN) {
110	      const msg = "Missing VITE_LIVEKIT_URL or VITE_LIVEKIT_TOKEN in .env";
111	      console.error(msg);
112	      setError(msg);
113	      setStatus("error");
