429	// Resolve when an agent participant joins the room (or null after timeout).
430	async function waitForAgent(room: Room, timeoutMs: number): Promise<RemoteParticipant | null> {
431	  const existing = Array.from(room.remoteParticipants.values()).find(
432	    (p) => p.kind === ParticipantKind.AGENT,
433	  );
434	  if (existing) return existing;
435	
436	  return new Promise((resolve) => {
437	    const timer = setTimeout(() => {
438	      room.off(RoomEvent.ParticipantConnected, handler);
439	      resolve(null);
440	    }, timeoutMs);
441	
442	    const handler = (participant: RemoteParticipant) => {
443	      if (participant.kind === ParticipantKind.AGENT) {
444	        clearTimeout(timer);
445	        room.off(RoomEvent.ParticipantConnected, handler);
446	        resolve(participant);
447	      }
448	    };
449	
450	    room.on(RoomEvent.ParticipantConnected, handler);
451	  });
