1	import { Fragment, type ReactNode } from "react";
2	import { ScrollArea } from "@/components/ui/scroll-area";
3	import { cn } from "@/lib/utils";
4	import type { FactCheckFlag, FactCheckVerdict, TranscriptSession } from "@/lib/types";
5	
6	type TranscriptPanelProps = {
7	  sessions: TranscriptSession[];
8	  flags: FactCheckFlag[];
9	  // Whether the most recent session is still receiving transcripts. Drives
10	  // the "Listening" indicator and styles the active block.
11	  isLive: boolean;
12	};
13	
14	const verdictHighlight: Record<FactCheckVerdict, string> = {
15	  "TRUE": "bg-green-100 text-green-900 ring-1 ring-green-300",
16	  "FALSE": "bg-red-100 text-red-900 ring-1 ring-red-300",
17	  "PARTIALLY TRUE": "bg-orange-100 text-orange-900 ring-1 ring-orange-300",
18	  "INCONCLUSIVE": "bg-slate-200 text-slate-800 ring-1 ring-slate-300",
19	};
20	
21	function highlightClassFor(verdict: string): string {
22	  return verdictHighlight[verdict as FactCheckVerdict] ?? verdictHighlight["INCONCLUSIVE"];
23	}
24	
25	// Strip leading/trailing punctuation/whitespace so that claim variants like
26	// "X.." or " X." still match the canonical span "X" in the transcript.
27	function normalizeForSearch(text: string): string {
28	  return text.toLowerCase().replace(/^[\s.,!?;:'"`-]+|[\s.,!?;:'"`-]+$/g, "");
29	}
30	
31	// Find every flag claim in the transcript text and wrap each matching span
32	// in a colored <mark>. Overlapping matches resolve by keeping the earliest
33	// (so we never double-wrap). Flags whose claim doesn't appear in the text
34	// are dropped — the side panel still shows them as cards.
35	function renderHighlightedTranscript(text: string, flags: FactCheckFlag[]): ReactNode {
36	  if (!text || flags.length === 0) return text;
37	
38	  type Match = { start: number; end: number; flag: FactCheckFlag };
39	  const lowered = text.toLowerCase();
40	  const matches: Match[] = [];
41	
42	  for (const flag of flags) {
43	    const needle = normalizeForSearch(flag.claim);
44	    if (!needle) continue;
45	    const idx = lowered.indexOf(needle);
46	    if (idx === -1) continue;
47	    matches.push({ start: idx, end: idx + needle.length, flag });
48	  }
49	
50	  if (matches.length === 0) return text;
51	
52	  matches.sort((a, b) => a.start - b.start);
53	
54	  // Drop matches that overlap an earlier match — pick the first one and skip the rest.
55	  const cleaned: Match[] = [];
56	  let cursor = 0;
57	  for (const m of matches) {
58	    if (m.start < cursor) continue;
59	    cleaned.push(m);
60	    cursor = m.end;
61	  }
62	
63	  const nodes: ReactNode[] = [];
64	  let pos = 0;
65	  cleaned.forEach((m, i) => {
66	    if (m.start > pos) nodes.push(<Fragment key={`t-${i}`}>{text.slice(pos, m.start)}</Fragment>);
67	    nodes.push(
68	      <mark
69	        key={`m-${i}`}
70	        className={cn("rounded px-1 py-0.5", highlightClassFor(m.flag.verdict))}
71	        title={m.flag.reasoning}
72	      >
73	        {text.slice(m.start, m.end)}
74	      </mark>,
75	    );
76	    pos = m.end;
77	  });
78	  if (pos < text.length) nodes.push(<Fragment key="t-tail">{text.slice(pos)}</Fragment>);
79	
80	  return nodes;
81	}
82	
83	export function TranscriptPanel({ sessions, flags, isLive }: TranscriptPanelProps) {
84	  return (
85	    <section className="flex min-h-0 flex-1 flex-col border-b border-border bg-background lg:border-b-0 lg:border-r">
