    --sidebar-primary: 166 84% 28%;
    --sidebar-primary-foreground: 0 0% 100%;
    --sidebar-accent: 166 50% 92%;
    --sidebar-accent-foreground: 166 84% 18%;
    --sidebar-border: 214 18% 84%;
    --sidebar-ring: 166 84% 28%;
  }

  .dark {
    --background: 215 28% 9%;
    --foreground: 210 20% 98%;

    --card: 215 24% 13%;
    --card-foreground: 210 20% 98%;

    --popover: 215 24% 13%;
